var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS006M0073-02: <color=#ffd34c>【기록-006】 검토 회의</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>……\\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>……\\nCCN No. FS006M0073-02：<color=#ffd34c>【記録-006】検討会議</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS006M0073-02: <color=#ffd34c>【Record-006】 Review Conference</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS007M0000-02: <color=#ffd34c>【記錄-006】 討論會議</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"흠.","JPN":"ふむ。","ENG":"Hmm.","TWN":"嗯。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그러고 보니 주시윤 군은 힐데 소대장이 데리고 왔다고 했었지?","JPN":"そういえば、アキヤマ・シリュウはヒルデ小隊長が連れてきたと言っていたな？","ENG":"So, Commander Hilde brought Joo Shiyoon?","TWN":"這麼說來，周時雲是被希爾德小隊長帶過來的？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그렇습니다.","JPN":"はい、そうです。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이전에 보고드린 대로 양친의 사망 직후 오갈 데 없는 주시윤 군을 스승님께서 제자로 삼은 것으로 알고 있습니다.","JPN":"以前に報告した通り両親の死後、引き取り手のなかったアキヤマ・シリュウを師匠が弟子としたそうです。","ENG":"As I previously reported, Master took him in as her apprentice because he had no place to go after his parents' death.","TWN":"就如之前的報告，父母去世後無處可去的周時雲君，被師父收為了弟子。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"어딘가 정상적인 고아원 같은 곳에나 맡기는 게 서로를 위해서 좋았을 것 같지만요.","JPN":"しかし、児童養護施設に預けた方がお互いにとってよかったのではないかと思いますが。","ENG":"Although it might have been better for both of them if he was sent to an orphanage.","TWN":"明明把他送到哪家孤兒院之類的地方，對我們大家都比較好。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......매정하구만.","JPN":"……冷たいな。","ENG":"That's cold.","TWN":"……真是無情呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"예전에는 좀 더...... 음...... 뭐랄까......","JPN":"昔はもう少し……、うん……何というか……","ENG":"You were more... um... sort of...","TWN":"你以前是更……嗯……怎麼說……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......그렇지, 감수성이 풍부한 성격이었던 것 같았는데.","JPN":"……感受性が豊かな性格だったと思うが。","ENG":"Yes, you were a lot more sensitive back in the days.","TWN":"……對，應該是個感受性更豐富的人啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......아드레날린 과다분비의 멍청이였다고 솔직하게 말씀하셔도 됩니다.","JPN":"……アドレナリン分泌過多のバカだったと、正直におっしゃってくださって大丈夫ですよ。","ENG":"You can be honest and say that I was an idiot who was always high on adrenaline.","TWN":"你直接說我是個腎上腺素分泌過多的笨蛋也沒關係。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......크흠! 크흠!","JPN":"……ゴホン！　ゴホン！","ENG":"Ahem! Ahem!","TWN":"……咳咳！咳咳！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그, 그 정도까지 생각한 건 아니네.","JPN":"そ、そんな風には思っていない。","ENG":"I-I wasn't thinking anything like that.","TWN":"我、我還沒想到那個程度。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그보다 주시윤 군의 양친에 대한 정보는 더 나온 게 있나?","JPN":"それより、アキヤマ・シリュウの両親に関する詳細情報はないのか？","ENG":"By the way, have you found anything more about Joo Shiyoon's parents?","TWN":"比起這個，有更多關於周時雲雙親的情報嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"회사로 데리고 온 건 그렇다 치고, 제자로까지 삼은 걸 보면 보통 관계는 아니었을 것 같은데......","JPN":"いくらなんでも、弟子として迎え入れたところを見ると、普通の関係ではなかったと思うのだが。","ENG":"I can understand Hilde bringing him here. But if she took him in as her apprentice, she must have had a close relationship with his parents...","TWN":"先不說把他帶到公司，連弟子都收了，看來關係並不一般……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"말씀드렸다시피 주시윤 군의 입사 전 정보에 대해서는 스승님께서 함구하시는 터라 별달리 말씀드릴 것이 없습니다.","JPN":"申し上げた通り、アキヤマ・シリュウの入社前の情報については、師匠が口を閉ざしているため他の記載はありません。","ENG":"As I told you before, Master is keeping any information regarding Joo Shiyoon's past a secret. I really don't have much to tell you.","TWN":"正如我所說，關於周時雲君入職前的情報，師父一直都是隻字不提，所以沒什麼特別能說的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그야 물론 그렇겠지만, 자네가 누가 뭘 숨긴다고 순순히 알겠습니다...... 하고 가만히 있을 성격도 아니지 않나?","JPN":"しかし……、だからと言って君が彼の情報を詳細不明のままにしておくわけがないだろう？","ENG":"I understand, but you're not the type of person who would just back off from secrets.","TWN":"那是當然，但你明明是一旦知道人家隱瞞著什麼……不會就此善罷甘休的性格吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"분명히 끝내주는 협잡과 멋진 공갈, 상상도 못할 회유와 우아한 압박으로 사람들의 약점을 후벼 파서 뭔가 쓸만한 걸 알아냈을 테지.","JPN":"必ず巧妙なイカサマや脅し、想像を絶する懐柔と圧迫などで他人の弱点をえぐり、何か使える情報を手にしているはずだ。","ENG":"I'm sure you came up with some great ways to swindle, intimidate, appease, and pressure people to find something useful.","TWN":"你一定會用驚人的騙術、酷炫的恐嚇、無法想像的收買、優雅的壓迫，挖出了人們心中的弱點並挖出有沒有可用的東西。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"말해 보게.","JPN":"勿体ぶらずに教えるんだ。","ENG":"So, tell me.","TWN":"說吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"역시...... 지난번에 추측한 대로 <color=#ff3636>[DATA EXPUNGED]</color> 인자 관련자인가?","JPN":"やはり……、この前推測した通り<color=#ff3636>[DATA EXPUNGED]</color>ファクター関連者か？","ENG":"Were they... related to the <color=#ff3636>[DATA EXPUNGED]</color> factor as we predicted before?","TWN":"難道……跟上次推測的一樣，是<color=#ff3636>[DATA_EXPUNGED]</color>因子相關者嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......사람을 대체 뭐로 보시는 건지 모르겠군요.","JPN":"……一体私をどういう人間だと思っていらっしゃるのですか？","ENG":"Is that really what you think of me?","TWN":"……真不知道您把我想成什麼樣的人了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"하지만...... 뭐, 알아낸 게 없는 건 아닙니다.","JPN":"しかし……、他に情報がないわけではありません。","ENG":"But... I did find something.","TWN":"但是……嗯，我也不是沒有任何新發現。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"하하, 역시!","JPN":"はは、やはりな！","ENG":"Hah hah, I knew it!","TWN":"哈哈，果然！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"시끄러워요.","JPN":"黙ってください。","ENG":"Shut it.","TWN":"很吵耶。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"기분 나쁘니까 그런 눈빛으로 보지 마시죠.","JPN":"そのような目で見られるのは、非常に不愉快です。","ENG":"And don't look at me like that. It's really creepy.","TWN":"我現在心情不好，請不要用那種眼神看我。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......알겠네. 보고나 계속하지.","JPN":"……わかった、わかった。報告を続けてくれ。","ENG":"Very well. Please continue.","TWN":"是，繼續說吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"실은 얼마 전에 주시윤 군이 회사 외부에서 비공식적인 전투 활동을 벌인 것이 확인되었습니다.","JPN":"実は、数日前にアキヤマ・シリュウが社外で非公式な戦闘活動を行ったことが確認されました。","ENG":"Recently, Joo Shiyoon engaged in unofficial combat activities outside the company.","TWN":"事實上在不久前，我確認到周時雲君在公司外部，進行了非正式的戰鬥。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"호오......?","JPN":"ほぉ……？","ENG":"Oh?","TWN":"哦……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"주시윤 군은 그 성격과는 별개로 사규나 근로수칙 등은 철저하게 지키는 편입니다.","JPN":"アキヤマ・シリュウは今まで、一度だって社内規程や勤労規則を破ったことはありません。","ENG":"Despite his rather free personality, Shiyoon usually sticks to company rules and labor regulations.","TWN":"撇開性格不說，周時雲君是個會徹底遵守公司規定和工作守則的人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"말하자면 <color=#ffd34c>공식적으로 책임질 일은 하지 않는다</color>라는 타입이죠.","JPN":"どちらかと言うと<color=#ffd34c>責任を負う可能性があることには関わらない</color>というタイプなんです。","ENG":"In other words, <color=#ffd34c>he never does anything for which he has to take official responsibility</color>.","TWN":"換句話說，就是<color=#ffd34c>不做自己需要負責的事情</color>的類型。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그리고 아시다시피 태스크포스 소속 카운터는 기본적으로 관할구역 외부에서의 개인적인 전투 행위를 금지하고 있습니다.","JPN":"そしてご存知の通り、タスクフォースカンパニー所属のカウンターは、基本的に管轄区域外での個人的な戦闘行為は禁止されています。","ENG":"And as you know, Counters working for TASKFORCE companies are prohibited from engaging in combat activities outside their jurisdiction.","TWN":"而且，您也知道，特遣勢力制裁者於管轄區外的個人戰鬥行為，基本上是被禁止。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"물론 대충 저지르고도 쉬쉬하는 경우가 많긴 하지만.......","JPN":"もちろん禁止行為を犯したとしても、もみ消す場合がほとんどですが……","ENG":"Of course, some of them just try and cover it up later...","TWN":"當然，還是會有人違反規定，但大致上都是偷偷地做……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"시윤 군의 성격상 어지간해서는 그런 귀찮은 일에 휘말릴지도 모르는 짓을 할 리가 없습니다.","JPN":"彼の性格上、余程のことがない限り、そのような面倒なことに巻き込まれるかもしれない行動を取るはずがありません。","ENG":"But I can't imagine Shiyoon doing such a thing when he knows that it could cause him trouble.","TWN":"然而以時雲君的性格來看，他是不可能會做那種讓自己捲入麻煩之中的事情。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그 말은.......","JPN":"つまり……？","ENG":"You mean...","TWN":"你的意思是……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"어지간하지 않은 이유가 있다는 뜻이죠.","JPN":"それなりに大きな理由があるということです。","ENG":"He had reasonable grounds to take the risk.","TWN":"意思是，他肯定有什麼特殊的理由。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그래서 말씀하신 것처럼 끝내주는 협잡과 우아한 압박으로 관련자들의 약점을 후벼 파낸 다음,","JPN":"そこで先ほどおっしゃられたように、巧みなイカサマと圧迫で関係者たちの弱点を利用し、","ENG":"So, as you said, I came up with great ways to swindle and pressure the concerned people,","TWN":"所以就像您所說的那樣，我用了驚人的騙術和優雅的壓迫，挖出了相關人的弱點後……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"당시 사건의 전말을 기록한 자료를 확보했습니다.","JPN":"その事件の全貌が記録された資料を確保しました。","ENG":"and acquired the information regarding the incident.","TWN":"我獲得了紀錄當時事件始末的資料。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"해당 지역은 CSE 2레벨 이상이 상시로 유지되는 오염지역으로 일반인들의 출입이 제한된 곳입니다.","JPN":"該当地域は常にCSEレベル2以上を感知する汚染地域で、一般人の出入りが制限されている場所です。","ENG":"The battle occurred inside a Corrupted Area blocked off from the public, where the CSE level is maintained above 2 at all times.","TWN":"該地區平時CSE維持在2級以上，是一般人禁止出入的污染地區。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그 외에 딱히 특별할 것은 없지만......","JPN":"それ以外に特別なことはありませんが……","ENG":"There is nothing else special about the area...","TWN":"除此之外沒什麼特別的地方，但是……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"전투 장소 인근에 미연고 묘소 두 개가 존재하는 것이 확인되었습니다.","JPN":"戦闘地域の近くに、無縁墓が二つ存在することが確認されました。","ENG":"But I did find two unidentified graves near the battle area.","TWN":"在戰鬥地點附近發現了兩個未知的墳墓"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......설마 파낸 건 아니겠지?","JPN":"……まさか掘り返したのか？","ENG":"You didn't dig them up, did you?","TWN":"……你沒有把墓挖開來吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"설마요. 인근 토양의 잔류 에너지 입자들을 수거했을 뿐입니다.","JPN":"まさか、そのようなことはしていません。近くの土壌の残留エネルギー粒子を回収しただけです。","ENG":"Of course not. I only retrieved the remaining energy particles from the surrounding soil.","TWN":"怎麼可能，我只是收集了附近土壤上殘留的能量粒子。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"재미있더군요.","JPN":"そして、実に面白い結果が出ました。","ENG":"It was very interesting.","TWN":"有意思。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"<color=#ff3636>[DATA EXPUNGED]</color> 레거시 데이터베이스에 등록된 주요 관리대상 생체정보와 일치하는 패턴이 나왔거든요.","JPN":"<color=#ff3636>[DATA EXPUNGED]</color>レガシーデータベースに登録された主要管理対象の生体情報と一致するパターンを検出しました。","ENG":"They matched the biometrics patterns of a key priority subject registered in the <color=#ff3636>[DATA EXPUNGED]</color> legacy database.","TWN":"結果出現了<color=#ff3636>[DATA_EXPUNGED]</color> 和舊資料庫中登錄的主要管理對象的生物資訊相吻合的樣本。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......코드명이 뭐지?","JPN":"……コード名は？","ENG":"What's the code name?","TWN":"……代號是什麼？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......<color=#ffd34c>용</color>입니다.","JPN":"……<color=#ffd34c>龍</color>です。","ENG":"<color=#ffd34c>Dragon</color>.","TWN":"……<color=#ffd34c>龍</color>。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......재미있겠군.","JPN":"……面白いな。","ENG":"That's interesting.","TWN":"……這一定很有趣。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그 자료, 내게도 보여 주겠나?","JPN":"その資料を、私にも見せてもらえるか？","ENG":"Can you show me that data as well?","TWN":"那份資料也能讓我看看嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"알겠습니다. 다음 보고시간에 지참하도록 하죠.","JPN":"承知しました。次の報告の時にお持ちしましょう。","ENG":"Yes. I'll bring them with me next time.","TWN":"好的。我會在下次的報告時候帶過來的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};